          '-filter_complex_threads', config.filters.threads,
          ...(startTime ? ['-ss', `${startTime}ms`] : []),
          '-i', encodeURI(url),
          ...(this.command.length != 0 ? [ '-af', this.command.join(',') ] : [] ),
          ...(endTime ? ['-t', `${endTime}ms`] : []),
